def execute_dynamic_script_aggregation(es_client: Elasticsearch, index_name: str, script_code: str, script_params: dict = None):
    """
    Executes a dynamic script aggregation on an Elasticsearch index.
    This assumes 'script.inline: true' is enabled in your Elasticsearch cluster's configuration.

    Args:
        es_client: The Elasticsearch client instance.
        index_name: The name of the index to perform the aggregation on.
        script_code: The Painless script code to execute. This typically comes from user input (e.g., req.json['script']).
        script_params: Optional dictionary of parameters to pass to the script.

    Returns:
        The aggregation results from Elasticsearch or an empty dictionary if an error occurs.
    """
    if script_params is None:
        script_params = {}

    # The aggregation query uses the 'script' field directly within an aggregation
    # (e.g., 'sum', 'avg', 'terms', 'min', 'max').
    # Here, we use a 'sum' aggregation as a common example for numeric script output.
    # For text output or custom logic to form buckets, a 'terms' aggregation with a script
    # might be more appropriate. For more complex calculations across documents,
    # 'scripted_metric' aggregation could be used.
    aggregation_query = {
        "size": 0,  # Set size to 0 to only return aggregation results, not hits
        "aggs": {
            "dynamic_script_result": {
                "sum": {
                    "script": {
                        "lang": "painless",  # Painless is the default and recommended scripting language
                        "source": script_code,
                        "params": script_params
                    }
                }
            }
        }
    }

    try:
        response = es_client.search(index=index_name, body=aggregation_query)
        return response.get('aggregations', {})
    except Exception as e:
        print(f"Error executing script aggregation: {e}")
        # In a real application, you might log this error and return a more structured error response
        return {}

def execute_dynamic_script_terms_aggregation(es_client: Elasticsearch, index_name: str, script_code: str, script_params: dict = None):
    """
    Executes a dynamic script-based 'terms' aggregation on an Elasticsearch index to create
    dynamic buckets. This assumes 'script.inline: true' is enabled.

    Args:
        es_client: The Elasticsearch client instance.
        index_name: The name of the index to perform the aggregation on.
        script_code: The Painless script code to execute, which should return the bucket key.
        script_params: Optional dictionary of parameters to pass to the script.

    Returns:
        The aggregation results from Elasticsearch or an empty dictionary if an error occurs.
    """
    if script_params is None:
        script_params = {}

    aggregation_query = {
        "size": 0,
        "aggs": {
            "dynamic_script_terms": {
                "terms": {
                    "script": {
                        "lang": "painless",
                        "source": script_code,
                        "params": script_params
                    },
                    "size": 10 # Adjust size for number of buckets as needed
                }
            }
        }
    }

    try:
        response = es_client.search(index=index_name, body=aggregation_query)
        return response.get('aggregations', {})
    except Exception as e:
        print(f"Error executing script terms aggregation: {e}")
